#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor gemm_relu_divide_impl_npu(const at::Tensor& x,
                                     const at::Tensor& w,
                                     const at::Tensor& b,
                                     const at::Tensor& divisor_tensor) {
    TORCH_CHECK(divisor_tensor.numel() == 1, \"divisor must be a scalar tensor\");
    const double divisor = divisor_tensor.item<double>();
    at::Tensor result = at::empty({x.size(0), w.size(0)}, x.options());
    EXEC_NPU_CMD(aclnnGemmReluDivideCustom, x, w, b, static_cast<float>(divisor), result);
    return result;
}

